impl Solution { pub fn earliest_finish_time(ls: Vec<i32>, ld: Vec<i32>, ws: Vec<i32>, wd: Vec<i32>) -> i32 { let black_f = |s1: &Vec<i32>, d1: &Vec<i32>, s2: &Vec<i32>, d2: &Vec<i32>| { let black_m1 = s1.iter().zip(d1.iter()).map(|(&s, &d)| s + d).min().unwrap(); s2.iter().zip(d2.iter()).map(|(&s, &d)| black_m1.max(s) + d).min().unwrap() }; black_f(&ls, &ld, &ws, &wd).min(black_f(&ws, &wd, &ls, &ld)) } }